import { Component, Element, h, Method, Prop } from '@stencil/core';
import { customTwMerge } from '../../../utils/utils';

@Component({
  tag: 'wdpr-combobox-tag',
  shadow: true,
  styles: `
    :host {
      display: inline-flex;
    }
  `,
})
export class WdprComboboxTag {
  private _tag?: HTMLSpanElement;

  @Element() el: HTMLWdprComboboxTagElement;

  @Prop() label: string = '';

  @Method()
  async focusTag() {
    this._tag?.focus();
  }

  private get _tagClasses(): string {
    const baseClasses =
      'inline-flex items-center justify-center px-100 rounded-050 bg-surface-status-neutral text-text-status-neutral text-component-small font-component-default leading-component-small tracking-02 whitespace-nowrap min-w-[48px] h-[22px]';
    const highlightClasses = 'focus-visible:outline focus-visible:outline-solid focus-visible:outline-025 focus-visible:outline-stroke-actionable-focused';

    return customTwMerge(baseClasses, highlightClasses);
  }

  render() {
    return (
      <span class={this._tagClasses} role="button" aria-label={`Remove ${this.label}`} tabindex="-1" ref={el => (this._tag = el as HTMLSpanElement)}>
        {this.label}
      </span>
    );
  }
}
